import { unstable_cacheTag as cacheTag, revalidateTag } from 'next/cache';

export async function getAllProducts() {
  'use cache';
  cacheTag('products');

  // Simulate database delay
  await new Promise((resolve) => setTimeout(resolve, 100));

  return [
    { id: 1, name: 'Laptop', price: 999, inventory: 42, availability: 'In stock' },
    { id: 2, name: 'Phone', price: 699, inventory: 18, availability: 'In stock' },
    { id: 3, name: 'Tablet', price: 499, inventory: 0, availability: 'Backorder' },
    { id: 4, name: 'Headphones', price: 199, inventory: 76, availability: 'In stock' },
    { id: 5, name: 'Watch', price: 299, inventory: 9, availability: 'Low stock' }
  ];
}

export async function syncLatestCatalog() {
  'use server';
  revalidateTag('products');
}

import { syncLatestCatalog, getAllProducts } from '@/lib/db';

function formatPrice(price) {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD'
  }).format(price);
}

export default async function Page() {
  const products = await getAllProducts();

  async function handleSync() {
    'use server';
    await syncLatestCatalog();
  }

  return (
    <main style={{ padding: 32, fontFamily: 'Arial, sans-serif' }}>
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 24 }}>
        <div>
          <h1 style={{ margin: 0 }}>Product Catalog</h1>
          <p style={{ margin: '8px 0 0', color: '#555' }}>
            Cached catalog data with background sync for fast day-to-day browsing.
          </p>
        </div>

        <form action={handleSync}>
          <button
            type="submit"
            style={{
              background: '#111827',
              color: 'white',
              border: 'none',
              borderRadius: 8,
              padding: '12px 16px',
              cursor: 'pointer'
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </header>

      <div style={{ marginTop: 32, overflowX: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ textAlign: 'left', borderBottom: '1px solid #e5e7eb' }}>
              <th style={{ padding: '12px 8px' }}>ID</th>
              <th style={{ padding: '12px 8px' }}>Name</th>
              <th style={{ padding: '12px 8px' }}>Price</th>
              <th style={{ padding: '12px 8px' }}>Inventory</th>
              <th style={{ padding: '12px 8px' }}>Availability</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id} style={{ borderBottom: '1px solid #f3f4f6' }}>
                <td style={{ padding: '12px 8px' }}>{product.id}</td>
                <td style={{ padding: '12px 8px', fontWeight: 600 }}>{product.name}</td>
                <td style={{ padding: '12px 8px' }}>{formatPrice(product.price)}</td>
                <td style={{ padding: '12px 8px' }}>{product.inventory}</td>
                <td style={{ padding: '12px 8px' }}>{product.availability}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </main>
  );
}

import type { Metadata } from 'next';

export const metadata: Metadata = {
  title: 'Product Catalog Admin',
  description: 'Admin catalog browsing with background sync'
};

export default function RootLayout({
  children
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <body>{children}</body>
    </html>
  );
}

